import React, { useState, useRef, useEffect  } from "react";
import { useNavigate, Link } from "react-router-dom";
import { Image, Form} from 'react-bootstrap'
import MainLayout from "../components/Layout";
import BASE_URL from "../config";
import CatalogueCard from "../components/CatalogueCard";

function Dashboard({ setModuleName }) {
   const cards = [
  { link: "/master/office",   title: "Office Management",  subtitle: "Insert, Update Office",   bgColor: "#eff6ff", iconColor: "#1d4ed8", icon: "fa fa-building" },
  { link: "/master/users",    title: "User Management",    subtitle: " Add, Verify and update employee details",    bgColor: "#f0fdf4", iconColor: "#15803d", icon: "fa fa-users"    },
  { link: "/master/products", title: "Product Catalogue",  subtitle: "Insert, Update Products", bgColor: "#fef9c3", iconColor: "#a16207", icon: "fa fa-box"      },
];

   useEffect(() => {
      setModuleName("Dashboard");
   }, []);

  return (  

      <div classNameName="container-fluid content-inner py-0 mt-2">
         <h5 className="fw-semibold mb-1 p-3">Master Entry</h5>
         <div className="row">
      {cards.map((card, index) => (
        <CatalogueCard key={index} {...card} />
      ))}
    </div>
         <div className="row g-3 px-3">
            <div className="col-4 col-md-2">
               <Link to="/master/office" className="text-decoration-none">
               <div className="acard">
               <div className="icon-wrap" style={{background:"#eff6ff", color:"#1d4ed8"}}>
                  <i className="fa fa-building"></i>
               </div>
               <p className="acard-title">Office Management</p>
               <p className="acard-delta delta-up">
                  <i className="ti ti-arrow-up" style={{fontSize:"12px"}}></i> Insert, Update Office
               </p>
               </div>
               </Link>
            </div>
            <div className="col-4 col-md-2">
               <Link to="/master/employee" className="text-decoration-none">
               <div className="acard">
               <div className="icon-wrap" style={{background:"#f0fdf4", color:"#16a34a"}}>
                  <i className="fa fa-users"></i>
               </div>
               <p className="acard-title">Employee Management</p>
               <p className="acard-delta delta-up">
                  <i className="ti ti-arrow-up" style={{fontSize:"12px"}}></i> Add, Verify and update employee details
               </p>
               </div></Link>
            </div>
         </div>
      </div>    
  );
}

export default Dashboard;
